import{o as n,c as s,a}from"./app.a612cc0f.js";const p='{"title":"Vue 组件","description":"","frontmatter":{},"headers":[{"level":2,"title":"vue 修饰符","slug":"vue-修饰符"},{"level":2,"title":"ASCII 键盘码修饰符","slug":"ascii-键盘码修饰符"},{"level":2,"title":"click 修饰符","slug":"click-修饰符"},{"level":2,"title":"form 修饰符","slug":"form-修饰符"},{"level":2,"title":"v-model 修饰符","slug":"v-model-修饰符"},{"level":2,"title":"props 双向绑定","slug":"props-双向绑定"},{"level":2,"title":"props validator 验证器","slug":"props-validator-验证器"}],"relativePath":"guide/vue/component.md","lastUpdated":1622976166280}',e={},t=[a('<h1 id="vue-组件"><a class="header-anchor" href="#vue-组件" aria-hidden="true">#</a> Vue 组件</h1><h2 id="vue-修饰符"><a class="header-anchor" href="#vue-修饰符" aria-hidden="true">#</a> vue 修饰符</h2><ul><li>stop 阻止事件继续传播</li><li>prevent 阻止标签默认行为</li><li>capture 使用事件捕获模式,即元素自身触发的事件先在此处处理，然后才交由内部元素进行处理</li><li>self 只当在 event.target 是当前元素自身时触发处理函数</li><li>once 事件将只会触发一次</li><li>passive 告诉浏览器你不想阻止事件的默认行为</li><li>native [vue 2.x]触发组件绑定一些事件，[vue 3.x]已经默认触发</li></ul><h2 id="ascii-键盘码修饰符"><a class="header-anchor" href="#ascii-键盘码修饰符" aria-hidden="true">#</a> ASCII 键盘码修饰符</h2><p>键盘和鼠标各个键位对应的 ASCII 码值</p><ul><li>keyCode 按下键盘都会触发 <code>shout</code>各键对应的 ASCII 码值 <code>&lt;input type=&quot;text&quot; @keyup.keyCode=&quot;shout(4)&quot;&gt;</code><code>if(event.keyCode&lt;48||event.keyCode&gt;57)event.returnValue=false; //禁止非数字字符输入 </code></li></ul><h2 id="click-修饰符"><a class="header-anchor" href="#click-修饰符" aria-hidden="true">#</a> click 修饰符</h2><ul><li><p>@click.prevent.self 会阻止所有的点击</p></li><li><p>@click.self.prevent 只会阻止对元素自身的点击</p></li><li><p>@click.capture \x3c!-- 添加事件监听器时使用事件捕获模式 --\x3e\x3c!-- 即元素自身触发的事件先在此处处理，然后才交由内部元素进行处理 --\x3e<code>&lt;div @click.capture=&quot;doThis&quot; /&gt;</code></p></li></ul><h2 id="form-修饰符"><a class="header-anchor" href="#form-修饰符" aria-hidden="true">#</a> form 修饰符</h2><ul><li><p>提交事件不再重载页面 <code>&lt;form v-on:submit.prevent=&quot;onSubmit&quot;&gt;&lt;/form&gt;</code></p></li><li><p>只有修饰符 <code>&lt;form v-on:submit.prevent&gt;&lt;/form&gt;</code></p></li><li><p>passive 告诉浏览器你不想阻止事件的默认行为 滚动事件的默认行为 (即滚动行为) 将会立即触发 ,而不会等待 <code>onScroll</code> 完成 这其中包含 <code>event.preventDefault()</code> 的情况 <code>&lt;div v-on:scroll.passive=&quot;onScroll&quot;&gt;...&lt;/div&gt;</code></p></li></ul><h2 id="v-model-修饰符"><a class="header-anchor" href="#v-model-修饰符" aria-hidden="true">#</a> v-model 修饰符</h2><ul><li><p>v-model.number 使用修饰符.number 可以将输入的数据转换为 Number 类型，否则虽然你输入的是数字.</p></li><li><p>v-model.trim 如果要自动过滤用户输入的首尾空白字符，可以给 v-model 添加 trim 修饰符 <code>&lt;input v-model.trim=&quot;msg&quot;&gt;</code></p></li><li><p>v-model.lazy input 在输入时，span 里的内容不做改变，当 input 失去焦点，触发 change 事件后 改变 span 的内容 <code>&lt;input v-model.lazy=&quot;msg&quot; @change=&quot;show&quot;&gt;</code></p></li></ul><h2 id="props-双向绑定"><a class="header-anchor" href="#props-双向绑定" aria-hidden="true">#</a> props 双向绑定</h2><div class="language-js line-numbers-mode"><pre><code><span class="token keyword">export</span> <span class="token keyword">default</span> <span class="token punctuation">{</span>\n  props<span class="token operator">:</span> <span class="token punctuation">{</span>\n    <span class="token comment">/**\n     * 双向绑定的代码内容\n     */</span>\n    modelValue<span class="token operator">:</span> <span class="token punctuation">{</span>\n      type<span class="token operator">:</span> <span class="token punctuation">[</span>String<span class="token punctuation">,</span> Object<span class="token punctuation">,</span> Array<span class="token punctuation">]</span><span class="token punctuation">,</span>\n      <span class="token keyword">default</span><span class="token operator">:</span> <span class="token keyword">null</span><span class="token punctuation">,</span>\n    <span class="token punctuation">}</span><span class="token punctuation">,</span>\n  <span class="token punctuation">}</span><span class="token punctuation">,</span>\n  <span class="token function">setup</span><span class="token punctuation">(</span><span class="token parameter">props<span class="token punctuation">,</span> <span class="token punctuation">{</span> emit <span class="token punctuation">}</span></span><span class="token punctuation">)</span> <span class="token punctuation">{</span>\n    <span class="token keyword">const</span> <span class="token function-variable function">btnSave</span> <span class="token operator">=</span> <span class="token punctuation">(</span><span class="token parameter">event</span><span class="token punctuation">)</span> <span class="token operator">=&gt;</span> <span class="token punctuation">{</span>\n      <span class="token keyword">let</span> _value <span class="token operator">=</span> <span class="token string">&#39;test&#39;</span><span class="token punctuation">;</span>\n      <span class="token comment">// 收到同步更新</span>\n      <span class="token function">emit</span><span class="token punctuation">(</span><span class="token string">&#39;update:modelValue&#39;</span><span class="token punctuation">,</span> _value<span class="token punctuation">)</span><span class="token punctuation">;</span>\n    <span class="token punctuation">}</span><span class="token punctuation">;</span>\n  <span class="token punctuation">}</span><span class="token punctuation">,</span>\n<span class="token punctuation">}</span><span class="token punctuation">;</span>\n</code></pre><div class="line-numbers-wrapper"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br><span class="line-number">17</span><br><span class="line-number">18</span><br></div></div><h2 id="props-validator-验证器"><a class="header-anchor" href="#props-validator-验证器" aria-hidden="true">#</a> props validator 验证器</h2><ul><li>vue props 下有验证器 validator 验证数据返回 true false 后，false 给 default 值</li></ul><div class="language-js line-numbers-mode"><pre><code><span class="token keyword">import</span> <span class="token punctuation">{</span> bll <span class="token punctuation">}</span> <span class="token keyword">from</span> <span class="token string">&#39;quick.lib&#39;</span><span class="token punctuation">;</span>\n<span class="token keyword">export</span> <span class="token keyword">default</span> <span class="token punctuation">{</span>\n  props<span class="token operator">:</span> <span class="token punctuation">{</span>\n    <span class="token comment">/** 名称 */</span>\n    named<span class="token operator">:</span> <span class="token punctuation">{</span>\n      type<span class="token operator">:</span> <span class="token punctuation">[</span>String<span class="token punctuation">,</span> Number<span class="token punctuation">]</span><span class="token punctuation">,</span>\n      <span class="token keyword">default</span><span class="token operator">:</span> <span class="token string">&#39;&#39;</span><span class="token punctuation">,</span>\n    <span class="token punctuation">}</span><span class="token punctuation">,</span>\n    <span class="token comment">/**是否显示关闭按钮 */</span>\n    closable<span class="token operator">:</span> Boolean<span class="token punctuation">,</span>\n    <span class="token comment">/** 主题颜色 */</span>\n    css<span class="token operator">:</span> <span class="token punctuation">{</span>\n      <span class="token comment">// required: true, // 定义该 prop 是否是必填项</span>\n      <span class="token comment">//验证数据</span>\n      <span class="token function">validator</span><span class="token punctuation">(</span><span class="token parameter">value</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>\n        <span class="token keyword">return</span> bll<span class="token punctuation">.</span>array<span class="token punctuation">.</span><span class="token function">test</span><span class="token punctuation">(</span>value<span class="token punctuation">,</span> <span class="token punctuation">[</span>\n          <span class="token string">&#39;default&#39;</span><span class="token punctuation">,</span>\n          <span class="token string">&#39;info&#39;</span><span class="token punctuation">,</span>\n          <span class="token string">&#39;primary&#39;</span><span class="token punctuation">,</span>\n          <span class="token string">&#39;success&#39;</span><span class="token punctuation">,</span>\n          <span class="token string">&#39;error&#39;</span><span class="token punctuation">,</span>\n          <span class="token string">&#39;warning&#39;</span><span class="token punctuation">,</span>\n        <span class="token punctuation">]</span><span class="token punctuation">)</span><span class="token punctuation">;</span>\n      <span class="token punctuation">}</span><span class="token punctuation">,</span>\n      <span class="token comment">// 默认值</span>\n      <span class="token keyword">default</span><span class="token punctuation">(</span><span class="token punctuation">)</span> <span class="token punctuation">{</span>\n        <span class="token keyword">return</span> <span class="token string">&#39;default&#39;</span><span class="token punctuation">;</span>\n      <span class="token punctuation">}</span><span class="token punctuation">,</span>\n    <span class="token punctuation">}</span><span class="token punctuation">,</span>\n  <span class="token punctuation">}</span><span class="token punctuation">,</span>\n<span class="token punctuation">}</span><span class="token punctuation">;</span>\n</code></pre><div class="line-numbers-wrapper"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br><span class="line-number">17</span><br><span class="line-number">18</span><br><span class="line-number">19</span><br><span class="line-number">20</span><br><span class="line-number">21</span><br><span class="line-number">22</span><br><span class="line-number">23</span><br><span class="line-number">24</span><br><span class="line-number">25</span><br><span class="line-number">26</span><br><span class="line-number">27</span><br><span class="line-number">28</span><br><span class="line-number">29</span><br><span class="line-number">30</span><br><span class="line-number">31</span><br></div></div>',17)];e.render=function(a,p,e,l,o,c){return n(),s("div",null,t)};export{p as __pageData,e as default};
